import React, { useEffect, useState } from 'react';
import { useForm, Controller } from 'react-hook-form';
import { Button, Box, Typography, Container, Paper, CircularProgress, MenuItem, TextField, Alert } from '@mui/material';
import InputField from '../components/InputField';
import { Editor } from '@tinymce/tinymce-react';
import api from '../utils/api';
import { useNavigate, useParams } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import {
    CHAR_LIMITS,
    DEPARTMENT_OPTIONS,
    CASE_STATUS_OPTIONS,
    LITIGATION_TYPE_OPTIONS,
    BENCH_OPTIONS
} from '../utils/constants';
import {
    requiredRule,
    charLimitRule,
    urlRule,
    dateMandatoryRules,
    dateOptionalRules,
    finalOrderDateRules
} from '../utils/validation';

function CaseEntryPage() {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();
    const [loading, setLoading] = useState(true);
    const [submitError, setSubmitError] = useState('');
    const [submitSuccess, setSubmitSuccess] = useState('');

    const {
        control,
        handleSubmit,
        setValue,
        reset,
        watch,
        formState: { errors, isSubmitting, isDirty }
    } = useForm({
        defaultValues: {
            case_id: '',
            case_name: '',
            date_of_institution: '',
            parties_involved_complainant: '',
            parties_involved_opposite: '',
            bench: '',
            sections_involved: '',
            status_of_case: '',
            type_of_litigation: '',
            relief_orders_prayed: '',
            important_directions_orders: '',
            date_of_next_hearing_order: '',
            outcome: '',
            date_of_final_order: '',
            link_of_order_judgment: '',
            department_name: user?.department_name || '',
        }
    });

    const getValues = watch();
    const tinymceApiKey = process.env.REACT_APP_TINYMCE_API_KEY;

    useEffect(() => {
        if (id) {
            setLoading(true);
            const fetchCase = async () => {
                try {
                    const response = await api.get(`/cases/${id}/`);
                    const caseData = response.data;

                    // Format dates for input fields
                    if (caseData.date_of_institution) caseData.date_of_institution = caseData.date_of_institution.split('T')[0];
                    if (caseData.date_of_next_hearing_order) caseData.date_of_next_hearing_order = caseData.date_of_next_hearing_order.split('T')[0];
                    if (caseData.date_of_final_order) caseData.date_of_final_order = caseData.date_of_final_order.split('T')[0];

                    reset(caseData);
                    setSubmitError('');
                } catch (error) {
                    console.error("Error fetching case:", error.response?.data || error.message);
                    setSubmitError('Failed to load case data for editing.');
                } finally {
                    setLoading(false);
                }
            };
            fetchCase();
        } else {
            // Set department for new cases if user is not admin
            if (!user?.is_admin) {
                setValue('department_name', user?.department_name || '');
            }
            setLoading(false);
        }
    }, [id, reset, user, setValue]);

    // Enhanced data validation and cleaning function
    const validateAndCleanData = (data) => {
        console.log("=== DATA VALIDATION AND CLEANING ===");
        console.log("Raw form data:", data);

        const cleanedData = { ...data };
        const validationErrors = [];

        // Clean and validate case_id
        if (cleanedData.case_id) {
            cleanedData.case_id = cleanedData.case_id.toString().trim();

            if (cleanedData.case_id.length === 0) {
                validationErrors.push("Case ID cannot be empty");
            } else if (cleanedData.case_id.length > 50) {
                validationErrors.push("Case ID is too long (max 50 characters)");
            } else if (cleanedData.case_id.includes(';') || cleanedData.case_id.includes('/')) {
                validationErrors.push("Case ID contains invalid characters (semicolon or forward slash)");
            }
        } else {
            validationErrors.push("Case ID is required");
        }

        // Clean and validate case_name - ENHANCED FOR BACKEND COMPATIBILITY
        if (cleanedData.case_name) {
            cleanedData.case_name = cleanedData.case_name.toString().trim();

            if (cleanedData.case_name.length === 0) {
                validationErrors.push("Case Name cannot be empty");
            } else if (cleanedData.case_name.length > 500) {
                validationErrors.push("Case Name is too long (max 500 characters)");
            } else {
                // Check for at least 2 words (backend requirement)
                const words = cleanedData.case_name.split(/\s+/).filter(word => word.length > 0);
                if (words.length < 2) {
                    validationErrors.push("Case Name must contain at least 2 words");
                }
            }
        } else {
            validationErrors.push("Case Name is required");
        }

        // Validate required dropdown fields with specific error messages
        const requiredDropdowns = [
            { field: 'status_of_case', name: 'Status of Case', validValues: CASE_STATUS_OPTIONS.map(opt => opt.value) },
            { field: 'type_of_litigation', name: 'Type of Litigation', validValues: LITIGATION_TYPE_OPTIONS.map(opt => opt.value) },
            { field: 'bench', name: 'Bench', validValues: BENCH_OPTIONS.map(opt => opt.value) },
            { field: 'department_name', name: 'Department', validValues: DEPARTMENT_OPTIONS.map(opt => opt.value) }
        ];

        requiredDropdowns.forEach(({ field, name, validValues }) => {
            if (!cleanedData[field] || cleanedData[field] === '') {
                validationErrors.push(`${name} is required`);
            } else if (!validValues.includes(cleanedData[field])) {
                validationErrors.push(`${name} has an invalid value: "${cleanedData[field]}". Valid options are: ${validValues.join(', ')}`);
                console.error(`Invalid ${field}:`, cleanedData[field]);
                console.error(`Valid values:`, validValues);
            }
        });

        // Enhanced date validation - ALIGNED WITH BACKEND
        if (cleanedData.date_of_institution) {
            const institutionDate = new Date(cleanedData.date_of_institution);
            if (isNaN(institutionDate.getTime())) {
                validationErrors.push("Invalid date of institution");
            } else {
                // Allow institution dates up to today only (not future)
                const today = new Date();
                today.setHours(23, 59, 59, 999);
                if (institutionDate > today) {
                    validationErrors.push("Date of institution cannot be in the future");
                }
                
                // Don't allow dates too far in the past
                const fiftyYearsAgo = new Date();
                fiftyYearsAgo.setFullYear(today.getFullYear() - 50);
                if (institutionDate < fiftyYearsAgo) {
                    validationErrors.push("Date of institution seems too far in the past (more than 50 years ago)");
                }
            }
        } else {
            validationErrors.push("Date of institution is required");
        }

        // Enhanced final order date validation - NO FUTURE DATES ALLOWED
        if (cleanedData.date_of_final_order) {
            const finalOrderDate = new Date(cleanedData.date_of_final_order);
            if (isNaN(finalOrderDate.getTime())) {
                validationErrors.push("Invalid date of final order");
            } else {
                // Check against institution date
                if (cleanedData.date_of_institution) {
                    const institutionDate = new Date(cleanedData.date_of_institution);
                    if (!isNaN(institutionDate.getTime()) && finalOrderDate < institutionDate) {
                        validationErrors.push("Date of final order cannot be before date of institution");
                    }
                }

                // BACKEND REQUIREMENT: No future dates for final orders
                const today = new Date();
                today.setHours(23, 59, 59, 999);
                
                if (finalOrderDate > today) {
                    validationErrors.push("Date of final order cannot be in the future");
                }
            }
        }

        // Enhanced next hearing date validation
        if (cleanedData.date_of_next_hearing_order) {
            const nextHearingDate = new Date(cleanedData.date_of_next_hearing_order);
            if (isNaN(nextHearingDate.getTime())) {
                validationErrors.push("Invalid date of next hearing/order");
            } else {
                // Check against institution date
                if (cleanedData.date_of_institution) {
                    const institutionDate = new Date(cleanedData.date_of_institution);
                    if (!isNaN(institutionDate.getTime()) && nextHearingDate < institutionDate) {
                        validationErrors.push("Date of next hearing cannot be before date of institution");
                    }
                }
            }
        }

        // Validate required text fields
        const requiredTextFields = [
            { field: 'parties_involved_complainant', name: 'Complainant parties' },
            { field: 'parties_involved_opposite', name: 'Opposite parties' },
            { field: 'sections_involved', name: 'Sections involved' },
            { field: 'outcome', name: 'Outcome' }
        ];

        requiredTextFields.forEach(({ field, name }) => {
            if (!cleanedData[field] || cleanedData[field].toString().trim().length === 0) {
                validationErrors.push(`${name} is required`);
            }
        });

        // Clean and validate HTML content from TinyMCE
        ['relief_orders_prayed', 'important_directions_orders'].forEach(field => {
            if (cleanedData[field]) {
                // Remove empty paragraphs and trim
                cleanedData[field] = cleanedData[field]
                    .replace(/<p><br><\/p>/g, '')
                    .replace(/<p>\s*<\/p>/g, '')
                    .replace(/<p>&nbsp;<\/p>/g, '')
                    .trim();

                // Check if content is actually empty after HTML removal
                const textContent = cleanedData[field].replace(/<[^>]*>/g, '').trim();
                if (!textContent) {
                    const fieldName = field === 'relief_orders_prayed' ? 'Relief/Orders Prayed' : 'Important Directions/Orders';
                    validationErrors.push(`${fieldName} cannot be empty`);
                    cleanedData[field] = '';
                }
            } else {
                const fieldName = field === 'relief_orders_prayed' ? 'Relief/Orders Prayed' : 'Important Directions/Orders';
                validationErrors.push(`${fieldName} is required`);
            }
        });

        // Validate URL if provided
        if (cleanedData.link_of_order_judgment && cleanedData.link_of_order_judgment.trim()) {
            const urlPattern = /^https?:\/\/.+/;
            if (!urlPattern.test(cleanedData.link_of_order_judgment.trim())) {
                validationErrors.push("Link of Order/Judgment must be a valid URL starting with http:// or https://");
            }
        }

        // Remove empty string values and replace with null for optional fields
        const optionalFields = ['date_of_next_hearing_order', 'date_of_final_order', 'link_of_order_judgment'];
        optionalFields.forEach(field => {
            if (cleanedData[field] === '') {
                cleanedData[field] = null;
            }
        });

        // Log final validation results
        console.log("=== VALIDATION RESULTS ===");
        console.log("Cleaned data:", cleanedData);
        console.log("Validation errors:", validationErrors);
        console.log("Validation passed:", validationErrors.length === 0);

        return {
            cleanedData,
            validationErrors
        };
    };

    const onSubmit = async (data) => {
        console.log("=== FORM SUBMISSION DEBUG ===");
        console.log("Raw form data:", data);
        console.log("Form errors:", errors);
        console.log("Form is valid:", Object.keys(errors).length === 0);

        setSubmitError('');
        setSubmitSuccess('');
        setLoading(true);

        try {
            // Enhanced data validation and cleaning
            const { cleanedData, validationErrors } = validateAndCleanData(data);

            if (validationErrors.length > 0) {
                setSubmitError(`Validation failed:\n• ${validationErrors.join('\n• ')}`);
                setLoading(false);
                return;
            }

            // Ensure department is set for non-admin users
            if (!user?.is_admin) {
                cleanedData.department_name = user.department_name;
            }

            console.log("=== FINAL DATA BEING SENT ===");
            console.log("Cleaned data:", cleanedData);

            let response;
            if (id) {
                response = await api.put(`/cases/${id}/`, cleanedData);
                setSubmitSuccess('Case updated successfully!');
            } else {
                response = await api.post('/cases/', cleanedData);
                setSubmitSuccess('Case created successfully!');
            }

            console.log("API Response:", response.data);

            // Navigate after a short delay to show success message
            setTimeout(() => {
                navigate('/cases');
            }, 2000);
        } catch (error) {
            console.error("=== DETAILED API ERROR ANALYSIS ===");
            console.error("Full error object:", error);
            console.error("Error response:", error.response);
            console.error("Error response data:", error.response?.data);
            console.error("Error response status:", error.response?.status);

            // More detailed error parsing
            if (error.response?.data) {
                let errorMessage = 'Submission failed with the following errors:\n\n';

                if (typeof error.response.data === 'object') {
                    for (const [key, value] of Object.entries(error.response.data)) {
                        if (Array.isArray(value)) {
                            errorMessage += `• ${key}: ${value.join(', ')}\n`;
                        } else if (typeof value === 'string') {
                            errorMessage += `• ${key}: ${value}\n`;
                        } else {
                            errorMessage += `• ${key}: ${JSON.stringify(value)}\n`;
                        }
                    }
                } else {
                    errorMessage += error.response.data;
                }

                setSubmitError(errorMessage);
            } else if (error.request) {
                setSubmitError('Network error: No response received from server. Please check your connection and try again.');
            } else {
                setSubmitError(`Request setup error: ${error.message}`);
            }
        } finally {
            setLoading(false);
        }
    };

    // Enhanced validation rules for frontend forms
    const enhancedCaseNameRules = {
        ...requiredRule('Case Name is mandatory.'),
        ...charLimitRule(CHAR_LIMITS.CASE_NAME, `Case Name cannot exceed ${CHAR_LIMITS.CASE_NAME} characters.`),
        validate: {
            twoWords: value => {
                const words = value?.trim().split(/\s+/).filter(word => word.length > 0);
                return (words && words.length >= 2) || 'Case Name must contain at least 2 words.';
            }
        }
    };

    // Create enhanced validation rules that use watch values
    const watchedValues = watch(); // Get all current form values
    
    const enhancedFinalOrderDateRules = {
        ...dateOptionalRules,
        validate: {
            ...dateOptionalRules.validate,
            notFuture: value => {
                if (!value) return true; // Optional field
                const selectedDate = new Date(value);
                const today = new Date();
                today.setHours(23, 59, 59, 999);
                return selectedDate <= today || 'Date of final order cannot be in the future.';
            },
            afterInstitution: value => {
                if (!value) return true;
                const institutionDate = watchedValues.date_of_institution;
                if (!institutionDate) return true;
                const selectedDate = new Date(value);
                const instDate = new Date(institutionDate);
                return selectedDate >= instDate || 'Date of final order cannot be before date of institution.';
            }
        }
    };

    if (loading && !submitSuccess) {
        return (
            <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '80vh' }}>
                <CircularProgress />
            </Box>
        );
    }

    return (
        <Container maxWidth="lg">
            <Paper sx={{ p: 4, mt: 4, mb: 4 }}>
                <Typography variant="h5" component="h1" gutterBottom align="center" sx={{ mb: 3 }}>
                    {id ? 'Edit Litigation Case' : 'Add New Litigation Case'}
                </Typography>

                {/* Success/Error Messages */}
                {submitSuccess && (
                    <Alert severity="success" sx={{ mb: 3 }}>
                        {submitSuccess}
                    </Alert>
                )}

                {submitError && (
                    <Alert severity="error" sx={{ mb: 3, whiteSpace: 'pre-line' }}>
                        {submitError}
                    </Alert>
                )}

                <form onSubmit={handleSubmit(onSubmit)}>
                    {/* Basic Information */}
                    <Box sx={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '20px', mb: 3 }}>
                        <InputField
                            name="case_id"
                            label="Case ID"
                            control={control}
                            charLimit={CHAR_LIMITS.CASE_ID}
                            spellCheck={false}
                            rules={{
                                ...requiredRule('Case ID is mandatory.'),
                                ...charLimitRule(CHAR_LIMITS.CASE_ID, `Case ID cannot exceed ${CHAR_LIMITS.CASE_ID} characters.`),
                                validate: {
                                    isNotChanged: value => !id || value === getValues().case_id || 'Case ID cannot be changed.',
                                    noSpecialChars: value => !/[;\/]/.test(value) || 'Case ID cannot contain semicolons or forward slashes.'
                                }
                            }}
                            disabled={!!id}
                        />
                        <InputField
                            name="case_name"
                            label="Case Name"
                            control={control}
                            charLimit={CHAR_LIMITS.CASE_NAME}
                            spellCheck={true}
                            rules={enhancedCaseNameRules}
                            helperText="Must contain at least 2 words"
                        />
                        <InputField
                            name="date_of_institution"
                            label="Date of Institution"
                            control={control}
                            type="date"
                            rules={dateMandatoryRules}
                            helperText="Cannot be in the future"
                        />
                        <InputField
                            name="department_name"
                            label="Department"
                            control={control}
                            select={true}
                            options={DEPARTMENT_OPTIONS}
                            rules={requiredRule('Department is mandatory.')}
                            disabled={!user?.is_admin}
                        />
                    </Box>

                    {/* Parties Information */}
                    <Typography variant="h6" sx={{ mb: 2, mt: 3 }}>Parties Information</Typography>
                    <InputField
                        name="parties_involved_complainant"
                        label="Parties Involved (Complainant/Applicant)"
                        control={control}
                        charLimit={CHAR_LIMITS.PARTIES_COMPLAINANT}
                        spellCheck={true}
                        rules={{
                            ...requiredRule('Complainant parties are mandatory.'),
                            ...charLimitRule(CHAR_LIMITS.PARTIES_COMPLAINANT, `This field cannot exceed ${CHAR_LIMITS.PARTIES_COMPLAINANT} characters.`),
                        }}
                        multiline
                        rows={2}
                    />
                    <InputField
                        name="parties_involved_opposite"
                        label="Parties Involved (Opposite Parties/Respondents)"
                        control={control}
                        charLimit={CHAR_LIMITS.PARTIES_OPPOSITE}
                        spellCheck={true}
                        rules={{
                            ...requiredRule('Opposite parties are mandatory.'),
                            ...charLimitRule(CHAR_LIMITS.PARTIES_OPPOSITE, `This field cannot exceed ${CHAR_LIMITS.PARTIES_OPPOSITE} characters.`),
                        }}
                        multiline
                        rows={2}
                    />

                    {/* Case Details */}
                    <Typography variant="h6" sx={{ mb: 2, mt: 3 }}>Case Details</Typography>
                    <Box sx={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '20px', mb: 3 }}>
                        <InputField
                            name="bench"
                            label="Bench"
                            control={control}
                            select={true}
                            options={BENCH_OPTIONS}
                            rules={requiredRule('Bench is mandatory.')}
                        />
                        <InputField
                            name="sections_involved"
                            label="Section(s) Involved"
                            control={control}
                            charLimit={CHAR_LIMITS.SECTIONS_INVOLVED}
                            spellCheck={true}
                            rules={{
                                ...requiredRule('Section(s) Involved are mandatory.'),
                                ...charLimitRule(CHAR_LIMITS.SECTIONS_INVOLVED, `This field cannot exceed ${CHAR_LIMITS.SECTIONS_INVOLVED} characters.`),
                            }}
                        />
                        <InputField
                            name="status_of_case"
                            label="Status of Case"
                            control={control}
                            select={true}
                            options={CASE_STATUS_OPTIONS}
                            rules={requiredRule('Status of Case is mandatory.')}
                        />
                        <InputField
                            name="type_of_litigation"
                            label="Type of Litigation"
                            control={control}
                            select={true}
                            options={LITIGATION_TYPE_OPTIONS}
                            rules={requiredRule('Type of Litigation is mandatory.')}
                        />
                    </Box>

                    {/* Important Dates */}
                    <Typography variant="h6" sx={{ mb: 2, mt: 3 }}>Important Dates</Typography>
                    <Box sx={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '20px', mb: 3 }}>
                        <InputField
                            name="date_of_next_hearing_order"
                            label="Date of Next Hearing/Order"
                            control={control}
                            type="date"
                            rules={dateOptionalRules}
                        />
                        <InputField
                            name="date_of_final_order"
                            label="Date of Final Order"
                            control={control}
                            type="date"
                            rules={enhancedFinalOrderDateRules}
                            helperText="Cannot be in the future"
                        />
                    </Box>

                    {/* Rich Text Fields */}
                    <Typography variant="h6" sx={{ mb: 2, mt: 3 }}>Detailed Information</Typography>

                    {/* Relief/Orders Prayed */}
                    <Box sx={{ mt: 2, mb: 2 }}>
                        <Typography variant="body2" sx={{ mb: 1, color: errors.relief_orders_prayed ? 'error.main' : 'text.secondary' }}>
                            Relief/Orders Prayed <span style={{ color: 'red' }}>*</span>
                            {errors.relief_orders_prayed && <span style={{ color: 'red' }}> ({errors.relief_orders_prayed.message})</span>}
                        </Typography>
                        <Controller
                            name="relief_orders_prayed"
                            control={control}
                            rules={{
                                ...requiredRule('Relief/Orders Prayed is mandatory.'),
                                validate: {
                                    notEmpty: value => {
                                        const textContent = value?.replace(/<[^>]*>/g, '').trim();
                                        return textContent && textContent.length > 0 || 'Relief/Orders Prayed cannot be empty.';
                                    },
                                    charLimit: value => {
                                        const textContent = value?.replace(/<[^>]*>/g, '').trim();
                                        return !textContent || textContent.length <= CHAR_LIMITS.RELIEF_ORDERS_PRAYED ||
                                            `This field cannot exceed ${CHAR_LIMITS.RELIEF_ORDERS_PRAYED} characters.`;
                                    }
                                }
                            }}
                            render={({ field }) => (
                                <Editor
                                    apiKey={tinymceApiKey}
                                    init={{
                                        plugins: 'advlist autolink lists link charmap preview anchor ' +
                                            'searchreplace visualblocks code fullscreen insertdatetime table code help wordcount',
                                        toolbar: 'undo redo | formatselect | bold italic backcolor | ' +
                                            'alignleft aligncenter alignright alignjustify | ' +
                                            'bullist numlist outdent indent | removeformat | help',
                                        height: 300,
                                        menubar: false,
                                        statusbar: true,
                                        browser_spellcheck: true,
                                        content_style: 'body { font-family: -apple-system, BlinkMacSystemFont, San Francisco, Segoe UI, Roboto, Helvetica Neue, sans-serif; font-size: 14px; }',
                                        paste_as_text: true,
                                        paste_auto_cleanup_on_paste: true,
                                        paste_remove_styles: true,
                                        paste_remove_styles_if_webkit: true,
                                        paste_strip_class_attributes: 'all',
                                    }}
                                    onEditorChange={(content) => field.onChange(content)}
                                    value={field.value}
                                    onBlur={field.onBlur}
                                />
                            )}
                        />
                    </Box>

                    {/* Important Directions/Orders */}
                    <Box sx={{ mt: 2, mb: 2 }}>
                        <Typography variant="body2" sx={{ mb: 1, color: errors.important_directions_orders ? 'error.main' : 'text.secondary' }}>
                            Important Directions/Orders <span style={{ color: 'red' }}>*</span>
                            {errors.important_directions_orders && <span style={{ color: 'red' }}> ({errors.important_directions_orders.message})</span>}
                        </Typography>
                        <Controller
                            name="important_directions_orders"
                            control={control}
                            rules={{
                                ...requiredRule('Important Directions/Orders is mandatory.'),
                                validate: {
                                    notEmpty: value => {
                                        const textContent = value?.replace(/<[^>]*>/g, '').trim();
                                        return textContent && textContent.length > 0 || 'Important Directions/Orders cannot be empty.';
                                    },
                                    charLimit: value => {
                                        const textContent = value?.replace(/<[^>]*>/g, '').trim();
                                        return !textContent || textContent.length <= CHAR_LIMITS.IMPORTANT_DIRECTIONS_ORDERS ||
                                            `This field cannot exceed ${CHAR_LIMITS.IMPORTANT_DIRECTIONS_ORDERS} characters.`;
                                    }
                                }
                            }}
                            render={({ field }) => (
                                <Editor
                                    apiKey={tinymceApiKey}
                                    init={{
                                        plugins: 'advlist autolink lists link charmap preview anchor ' +
                                            'searchreplace visualblocks code fullscreen insertdatetime table code help wordcount',
                                        toolbar: 'undo redo | formatselect | bold italic backcolor | ' +
                                            'alignleft aligncenter alignright alignjustify | ' +
                                            'bullist numlist outdent indent | removeformat | help',
                                        height: 300,
                                        menubar: false,
                                        statusbar: true,
                                        browser_spellcheck: true,
                                        content_style: 'body { font-family: -apple-system, BlinkMacSystemFont, San Francisco, Segoe UI, Roboto, Helvetica Neue, sans-serif; font-size: 14px; }',
                                        paste_as_text: true,
                                        paste_auto_cleanup_on_paste: true,
                                        paste_remove_styles: true,
                                        paste_remove_styles_if_webkit: true,
                                        paste_strip_class_attributes: 'all',
                                    }}
                                    onEditorChange={(content) => field.onChange(content)}
                                    value={field.value}
                                    onBlur={field.onBlur}
                                />
                            )}
                        />
                    </Box>

                    {/* Additional Information */}
                    <Typography variant="h6" sx={{ mb: 2, mt: 3 }}>Additional Information</Typography>
                    <InputField
                        name="outcome"
                        label="Outcome"
                        control={control}
                        multiline
                        rows={3}
                        charLimit={CHAR_LIMITS.OUTCOME}
                        spellCheck={true}
                        rules={{
                            ...requiredRule('Outcome is mandatory.'),
                            ...charLimitRule(CHAR_LIMITS.OUTCOME, `Outcome cannot exceed ${CHAR_LIMITS.OUTCOME} characters.`)
                        }}
                    />
                    <InputField
                        name="link_of_order_judgment"
                        label="Link of Order/Judgment"
                        control={control}
                        charLimit={CHAR_LIMITS.LINK_OF_ORDER_JUDGMENT}
                        spellCheck={false}
                        rules={urlRule('Please enter a valid URL for the order/judgment (e.g., https://example.com).')}
                    />

                    {/* Action Buttons */}
                    <Box sx={{ display: 'flex', justifyContent: 'flex-end', gap: 2, mt: 4 }}>
                        <Button
                            variant="outlined"
                            onClick={() => navigate('/cases')}
                            disabled={isSubmitting}
                            size="large"
                        >
                            Cancel
                        </Button>
                        <Button
                            type="submit"
                            variant="contained"
                            color="primary"
                            disabled={isSubmitting || loading}
                            startIcon={isSubmitting || loading ? <CircularProgress size={20} color="inherit" /> : null}
                            size="large"
                        >
                            {id ? 'Update Case' : 'Add Case'}
                        </Button>
                    </Box>
                </form>
            </Paper>
        </Container>
    );
}

export default CaseEntryPage;
